-- Enhanced NY Consulting Agreement Template v2
-- Improvements: FIFA compliance, NY Labor Law 193, NY Executive Law, NY-specific IP/work-for-hire,
-- Whistleblower protections, GBL 349, NY SHIELD Act, Professional licensing, NY Arbitration, Tax withholding

INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'consulting_agreement',
  'us_new_york',
  2,
  'Consulting Services Agreement (New York)',
  'This Consulting Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, a {{party_a_entity_type}} organized under the laws of {{party_a_state}}, with its principal place of business at {{party_a_address}} ("Client"), and {{party_b_company}}, a {{party_b_entity_type}} with an address at {{party_b_address}} ("Consultant").',
  'WHEREAS, Client desires to engage Consultant to provide professional consulting services as described herein;
WHEREAS, Consultant represents that it possesses the expertise, qualifications, and any required professional licenses to provide such services;
WHEREAS, the parties intend this Agreement to comply with applicable New York law, including (where applicable) the Freelance Isn''t Free Act (New York City Administrative Code § 20-927 et seq. and/or New York Labor Law Article 44);
NOW, THEREFORE, in consideration of the mutual covenants contained herein and other good and valuable consideration, the receipt and sufficiency of which are hereby acknowledged, the Parties agree as follows:',
  '[{"id":"engagement","title":"1. ENGAGEMENT AND SERVICES","content":"1.1 Engagement. Client hereby engages Consultant, and Consultant hereby accepts such engagement, to provide the consulting services described in Exhibit A or {{services_description}} (the \"Services\").\n\n1.2 Standard of Performance. Consultant shall perform the Services in a professional and workmanlike manner, consistent with the highest standards of Consultant''s profession, in accordance with generally accepted industry standards, and in compliance with all applicable federal, state, and local laws, including New York law.\n\n1.3 Deliverables. Consultant shall deliver any deliverables specified in Exhibit A or {{services_description}} in accordance with the timeline and specifications set forth therein. All deliverables shall be complete, accurate, and meet the specifications agreed upon by the Parties.\n\n1.4 Client Cooperation. Client shall provide Consultant with reasonable access to personnel, information, systems, and resources necessary for Consultant to perform the Services. Client shall designate a point of contact for day-to-day matters.\n\n1.5 Changes. Any changes to the scope, timeline, or fees for the Services must be agreed in writing by both Parties through a signed amendment or change order.\n\n1.6 Professional Licensing. Consultant represents and warrants that it holds all licenses, permits, certifications, and registrations required under applicable federal, state (including New York), and local laws to perform the Services. Consultant shall maintain such licenses in good standing throughout the term. Consultant shall promptly notify Client of any suspension, revocation, or material limitation of any required license.","type":"standard","order":1},{"id":"fees_payment","title":"2. FEES AND PAYMENT","content":"2.1 Fees. Client shall pay Consultant the fees set forth in Exhibit A or {{services_description}}, which may include: (a) a fixed fee of {{payment_amount}}; and/or (b) an hourly rate of {{hourly_rate}}; and/or (c) such other fee structure as specified therein.\n\n2.2 Invoicing. Consultant shall submit detailed invoices in accordance with Exhibit A or {{services_description}}, or monthly in arrears if not specified. Each invoice shall itemize services performed, hours worked (if applicable), expenses (if pre-approved), and applicable taxes.\n\n2.3 Payment Terms. Client shall pay undisputed invoices within thirty (30) days of receipt. Late payments shall accrue interest at 1.5% per month or the maximum rate permitted by New York law, whichever is less.\n\n2.4 Freelance Isn''t Free Act Compliance. Where the total compensation under this Agreement equals or exceeds $800 (Eight Hundred Dollars) and the services are completed within 120 days, this Agreement is subject to the New York Freelance Isn''t Free Act. In such cases: (a) Client shall pay Consultant within 30 days of completion of the Services (or if this Agreement provides for payment upon occurrence of a milestone, within 30 days after such milestone occurs); (b) Consultant may be entitled to double damages, injunctive relief, and reasonable attorneys'' fees for late payment or non-payment as provided by applicable law.\n\n2.5 Expenses. Unless pre-approved in writing by Client, Consultant shall bear all expenses incurred in performing the Services. Pre-approved expenses shall be reimbursed at cost upon submission of receipts.\n\n2.6 Taxes. Consultant is an independent contractor and is solely responsible for all federal, state, and local taxes arising from fees received, including New York State income tax, New York City income tax (if applicable), and self-employment taxes. Client will not withhold payroll taxes, FICA, or any other deductions from payments to Consultant.\n\n2.7 NY Labor Law Section 193 Acknowledgment. The Parties acknowledge that New York Labor Law Section 193 restricts wage deductions. To the extent any provision of this Agreement could be construed as requiring a deduction from wages in violation of Section 193, such provision shall be interpreted in a manner consistent with applicable law or shall be unenforceable to that extent.\n\n2.8 Tax Withholding Acknowledgment. Consultant acknowledges responsibility for timely payment of estimated taxes to federal, New York State, and (if applicable) New York City tax authorities. Consultant shall provide Client with a completed IRS Form W-9 upon request.","type":"standard","order":2},{"id":"consultant_status","title":"3. CONSULTANT STATUS","content":"3.1 Independent Contractor. Consultant is an independent contractor and not an employee, worker, agent, joint venturer, or partner of Client. Nothing in this Agreement shall be construed to create an employment relationship, agency, partnership, or joint venture.\n\n3.2 Control. Consultant shall determine the manner, method, and means of performing the Services, subject to the requirements of this Agreement and achievement of the agreed-upon deliverables. Client''s right to control is limited to the results of the Services, not the means by which they are accomplished.\n\n3.3 New York Classification. The Parties intend that Consultant be properly classified as an independent contractor under all applicable laws, including New York Labor Law, the Internal Revenue Code, and applicable common law tests. The Parties have structured this Agreement to reflect an independent contractor relationship.\n\n3.4 No Employee Benefits. Consultant is not entitled to participate in any employee benefit plans, programs, or arrangements of Client, including health insurance, retirement plans, paid time off, or workers'' compensation coverage.\n\n3.5 Other Engagements. Consultant may provide services to other clients during the term of this Agreement, provided that such engagements do not: (a) conflict with Consultant''s obligations under this Agreement; (b) involve disclosure of Client''s Confidential Information; or (c) create a conflict of interest.\n\n3.6 Subcontractors. Consultant may engage subcontractors or assistants only with Client''s prior written consent. Consultant shall remain fully responsible for the work of any approved subcontractors and shall ensure they are bound by confidentiality and IP assignment obligations no less protective than those in this Agreement.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM AND TERMINATION","content":"4.1 Term. This Agreement commences on the Effective Date and continues until {{expiration_date}}, or if no expiration date is specified, until the Services are completed, unless earlier terminated as provided herein.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement for any reason by giving {{notice_period}} days'' written notice to the other Party (or 14 days if no notice period is specified).\n\n4.3 Termination for Cause. Either Party may terminate this Agreement immediately upon written notice if the other Party: (a) materially breaches this Agreement and fails to cure such breach within ten (10) days after receiving written notice specifying the breach; (b) becomes insolvent, files for bankruptcy, or has a receiver appointed for its assets; (c) commits fraud, gross negligence, or willful misconduct; or (d) has a required professional license suspended or revoked.\n\n4.4 Effect of Termination. Upon termination or expiration: (a) Consultant shall immediately cease performing the Services and deliver to Client all completed and in-progress Work Product, Client materials, and Confidential Information; (b) Client shall pay Consultant for all Services properly performed through the effective date of termination, subject to applicable payment terms and any offset for damages caused by Consultant''s breach; (c) each Party shall return or destroy the other Party''s Confidential Information.\n\n4.5 Survival. The following provisions shall survive termination or expiration: Sections 5 (Intellectual Property), 6 (Confidentiality), 7 (Warranties and Liability), 8 (Indemnification), 9 (Dispute Resolution), and 10 (General Provisions), as well as any other provisions that by their nature should survive.","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY","content":"5.1 Work Product. \"Work Product\" means all inventions, discoveries, developments, improvements, designs, works of authorship, documentation, software, code, data, reports, analyses, deliverables, and other materials conceived, created, developed, or reduced to practice by Consultant, alone or jointly with others, in the course of performing the Services.\n\n5.2 Work Made for Hire. To the maximum extent permitted by law, all Work Product that qualifies as a \"work made for hire\" under the U.S. Copyright Act (17 U.S.C. § 101) shall be deemed a work made for hire, with Client as the author and owner of all copyright therein.\n\n5.3 Assignment. To the extent any Work Product does not qualify as a work made for hire, Consultant hereby irrevocably assigns to Client all right, title, and interest in and to such Work Product worldwide, including all patents, copyrights, trade secrets, trademarks, and other intellectual property rights therein. This assignment is effective upon creation of each item of Work Product and requires no further action.\n\n5.4 Further Assurances. Consultant agrees to execute and deliver any documents, and to take any actions, that Client may reasonably request to perfect, register, maintain, or enforce Client''s rights in the Work Product. Consultant hereby irrevocably appoints Client as Consultant''s attorney-in-fact to execute such documents if Consultant fails to do so within ten (10) days of request.\n\n5.5 Background IP. Consultant retains all rights in intellectual property owned or developed by Consultant prior to or independent of this Agreement (\"Background IP\"). Consultant shall identify any Background IP in writing before incorporating it into Work Product. If Background IP is incorporated into Work Product with Client''s consent, Consultant grants Client a perpetual, irrevocable, worldwide, royalty-free, fully paid-up, sublicensable license to use, reproduce, modify, distribute, display, and create derivative works of such Background IP solely as embodied in the Work Product.\n\n5.6 Moral Rights. Consultant waives and agrees not to assert any moral rights or similar rights (including rights of attribution and integrity) in the Work Product to the fullest extent permitted by applicable law, including under the Visual Artists Rights Act and any state equivalents.\n\n5.7 Third-Party Materials. Consultant shall not incorporate any third-party materials, open-source software, or other intellectual property into the Work Product without: (a) Client''s prior written approval; and (b) ensuring appropriate licenses are in place. Consultant shall disclose all third-party materials and license terms.\n\n5.8 Inventions Assignment. Consultant assigns to Client all rights in any inventions, discoveries, or improvements conceived or reduced to practice while performing the Services, and agrees to disclose them promptly and assist with patent applications at Client''s expense.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY AND DATA PROTECTION","content":"6.1 Confidential Information. \"Confidential Information\" means all non-public information disclosed by one Party (the \"Disclosing Party\") to the other Party (the \"Receiving Party\") that: (a) is designated as confidential or proprietary; or (b) a reasonable person would understand to be confidential given its nature and the circumstances of disclosure. Confidential Information includes, without limitation, business plans, financial information, customer lists, technical data, trade secrets, software, and the terms of this Agreement.\n\n6.2 Obligations. The Receiving Party shall: (a) use Confidential Information solely for purposes of this Agreement; (b) protect it with at least the same degree of care used to protect its own confidential information, but not less than reasonable care; (c) not disclose it to third parties except to employees, contractors, and advisors who have a need to know and are bound by confidentiality obligations at least as protective as these; and (d) promptly notify the Disclosing Party of any unauthorized disclosure.\n\n6.3 Exclusions. Confidential Information does not include information that: (a) is or becomes publicly available through no fault of the Receiving Party; (b) was rightfully in the Receiving Party''s possession before disclosure; (c) is rightfully received from a third party without confidentiality restrictions; or (d) is independently developed without use of Confidential Information.\n\n6.4 Compelled Disclosure. If the Receiving Party is legally compelled to disclose Confidential Information, it shall: (a) provide prompt notice to the Disclosing Party (if legally permitted); (b) cooperate with the Disclosing Party''s efforts to obtain protective treatment; and (c) disclose only the minimum information legally required.\n\n6.5 NY SHIELD Act Compliance. If Consultant receives, processes, or has access to \"private information\" of New York residents (as defined in the New York Stop Hacks and Improve Electronic Data Security Act, N.Y. Gen. Bus. Law § 899-bb), Consultant shall: (a) implement and maintain reasonable safeguards to protect the security, confidentiality, and integrity of such information; (b) promptly notify Client of any data breach affecting such information; and (c) cooperate with Client in complying with breach notification requirements under NY Gen. Bus. Law § 899-aa.\n\n6.6 Return of Materials. Upon termination or Client''s request, Consultant shall promptly return or securely destroy (at Client''s election) all Confidential Information and certify such destruction in writing.\n\n6.7 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held criminally or civilly liable under any federal or state trade secret law for the disclosure of a trade secret made: (a) in confidence to a government official or attorney solely for the purpose of reporting or investigating a suspected violation of law; or (b) in a complaint or other document filed in a lawsuit or other proceeding, if filed under seal.\n\n6.8 Duration. Confidentiality obligations shall survive termination of this Agreement for {{confidentiality_period}} years (or 5 years if not specified), except that obligations regarding trade secrets shall continue for as long as such information remains a trade secret.","type":"standard","order":6},{"id":"warranties_liability","title":"7. WARRANTIES AND LIABILITY","content":"7.1 Consultant Representations and Warranties. Consultant represents and warrants that: (a) it has full power and authority to enter into this Agreement and perform its obligations; (b) the Services will be performed in a professional, workmanlike manner consistent with industry standards; (c) the Work Product will be original and will not infringe, misappropriate, or violate any third-party intellectual property or other rights; (d) Consultant will comply with all applicable laws in performing the Services; (e) Consultant holds and will maintain all required professional licenses; and (f) Consultant has not entered into any agreement that would prevent performance of its obligations hereunder.\n\n7.2 Client Representations and Warranties. Client represents and warrants that: (a) it has full power and authority to enter into this Agreement; (b) materials provided to Consultant do not infringe third-party rights; and (c) Client will comply with applicable laws regarding the engagement of independent contractors.\n\n7.3 Disclaimer. EXCEPT AS EXPRESSLY SET FORTH HEREIN, NEITHER PARTY MAKES ANY OTHER WARRANTIES, EXPRESS OR IMPLIED, INCLUDING WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE, TITLE, OR NON-INFRINGEMENT.\n\n7.4 Limitation of Liability. EXCEPT FOR BREACHES OF CONFIDENTIALITY, INDEMNIFICATION OBLIGATIONS, OR A PARTY''S GROSS NEGLIGENCE, FRAUD, OR WILLFUL MISCONDUCT: (a) NEITHER PARTY SHALL BE LIABLE FOR ANY INDIRECT, INCIDENTAL, SPECIAL, CONSEQUENTIAL, PUNITIVE, OR EXEMPLARY DAMAGES, INCLUDING LOST PROFITS, EVEN IF ADVISED OF THE POSSIBILITY OF SUCH DAMAGES; AND (b) EACH PARTY''S TOTAL AGGREGATE LIABILITY SHALL NOT EXCEED THE GREATER OF (i) THE FEES PAID OR PAYABLE UNDER THIS AGREEMENT IN THE TWELVE (12) MONTHS PRECEDING THE CLAIM, OR (ii) {{liability_cap}} (if specified).\n\n7.5 Exceptions. Nothing in this Agreement shall limit liability for: (a) death or personal injury caused by negligence; (b) fraud or fraudulent misrepresentation; (c) willful misconduct; (d) infringement of intellectual property rights; or (e) any liability that cannot be limited by applicable law.\n\n7.6 Freelance Isn''t Free Act. Notwithstanding the foregoing, nothing in this Section limits Consultant''s rights or Client''s obligations under the New York Freelance Isn''t Free Act, including the right to recover double damages, attorneys'' fees, injunctive relief, and other remedies as provided by law.\n\n7.7 Essential Purpose. The Parties agree that the limitations of liability reflect a reasonable allocation of risk and are fundamental elements of the basis of the bargain between the Parties.","type":"negotiable","order":7},{"id":"indemnification","title":"8. INDEMNIFICATION","content":"8.1 Consultant Indemnity. Consultant shall indemnify, defend, and hold harmless Client and its officers, directors, employees, agents, successors, and assigns from and against any and all claims, damages, losses, liabilities, costs, and expenses (including reasonable attorneys'' fees) arising out of or relating to: (a) Consultant''s negligence, gross negligence, or willful misconduct in performing the Services; (b) any claim that the Work Product (excluding portions derived from Client-provided materials) infringes, misappropriates, or violates any third-party intellectual property or other rights; (c) Consultant''s breach of any representation, warranty, or obligation under this Agreement; (d) Consultant''s failure to properly pay taxes or maintain required insurance; or (e) any claim by Consultant''s employees or subcontractors regarding employment status, benefits, or wages.\n\n8.2 Client Indemnity. Client shall indemnify, defend, and hold harmless Consultant from and against any and all claims, damages, losses, liabilities, costs, and expenses (including reasonable attorneys'' fees) arising out of or relating to: (a) Client-provided materials infringing third-party rights; (b) Client''s misuse of the Work Product beyond the scope of this Agreement; or (c) Client''s breach of this Agreement.\n\n8.3 Indemnification Procedure. The indemnified Party shall: (a) provide prompt written notice of any claim (provided that failure to provide timely notice shall not relieve the indemnifying Party except to the extent materially prejudiced); (b) allow the indemnifying Party to control the defense and settlement (provided that no settlement shall admit liability or impose obligations on the indemnified Party without consent); and (c) provide reasonable cooperation at the indemnifying Party''s expense. The indemnified Party may participate in the defense with its own counsel at its own expense.","type":"negotiable","order":8},{"id":"dispute_resolution","title":"9. DISPUTE RESOLUTION AND COMPLIANCE","content":"9.1 Informal Resolution. Before initiating formal dispute resolution, the Parties shall attempt in good faith to resolve any dispute through informal negotiation. A Party shall provide written notice describing the dispute, and the Parties shall meet (in person or by video conference) within fifteen (15) days to attempt resolution.\n\n9.2 Mediation. If informal resolution fails, either Party may initiate non-binding mediation administered by JAMS or another mutually agreed mediator in {{venue_county}} County, New York. The Parties shall share mediation costs equally.\n\n9.3 Arbitration. If mediation fails within thirty (30) days of initiation, either Party may demand binding arbitration administered by the American Arbitration Association (\"AAA\") in accordance with its Commercial Arbitration Rules. The arbitration shall be conducted in {{venue_county}} County, New York, before a single arbitrator with relevant legal expertise. The arbitrator''s decision shall be final and binding, and judgment may be entered in any court of competent jurisdiction. The arbitrator may award attorneys'' fees to the prevailing party.\n\n9.4 Injunctive Relief. Notwithstanding the foregoing, either Party may seek injunctive or other equitable relief from any court of competent jurisdiction to prevent irreparable harm, including protection of Confidential Information or intellectual property rights.\n\n9.5 Small Claims Exception. Either Party may bring claims within the jurisdiction of small claims court without first pursuing mediation or arbitration.\n\n9.6 Freelance Isn''t Free Act Remedies. Notwithstanding this Section, Consultant retains all rights to file complaints with applicable New York agencies (including the NYC Department of Consumer and Worker Protection and New York State Department of Labor) and to pursue all remedies available under the Freelance Isn''t Free Act, including court proceedings.\n\n9.7 No Retaliation. Client shall not take any adverse action against Consultant, including threatening, intimidating, disciplining, harassing, blacklisting, or denying future work opportunities, for: (a) exercising any right under this Agreement or applicable law; (b) filing a complaint with any government agency; or (c) participating in any investigation or proceeding regarding Consultant''s rights.\n\n9.8 NY Executive Law Compliance. The Parties shall comply with the New York Human Rights Law (NY Executive Law Article 15), and neither Party shall discriminate against the other or any third party on the basis of age, race, creed, color, national origin, sexual orientation, gender identity, military status, sex, disability, marital status, domestic violence victim status, or any other protected characteristic.\n\n9.9 Whistleblower Protection. Consultant is protected under New York Labor Law Section 740 and other applicable whistleblower laws. Client shall not retaliate against Consultant for reporting, in good faith, violations of law, rule, or regulation that create a substantial and specific danger to public health or safety, or that constitute health care fraud.","type":"standard","order":9},{"id":"general","title":"10. GENERAL PROVISIONS","content":"10.1 Governing Law. This Agreement shall be governed by and construed in accordance with the laws of the State of New York, without regard to its conflict of laws principles. The United Nations Convention on Contracts for the International Sale of Goods shall not apply.\n\n10.2 Venue. Subject to Section 9, the Parties consent to the exclusive personal jurisdiction and venue of the state and federal courts located in {{venue_county}} County, New York, for any legal proceedings.\n\n10.3 Notices. All notices required or permitted under this Agreement shall be in writing and delivered by: (a) personal delivery; (b) nationally recognized overnight courier; (c) certified mail, return receipt requested; or (d) email with confirmation of receipt. Notices are effective upon receipt. Notices shall be sent to the addresses set forth in the signature block, or to such other address as a Party may designate in writing.\n\n10.4 Assignment. Neither Party may assign or transfer this Agreement or any rights or obligations hereunder without the other Party''s prior written consent, except that either Party may assign to a successor in a merger, acquisition, or sale of substantially all assets. Any attempted assignment in violation of this Section is void. This Agreement binds and inures to the benefit of the Parties'' permitted successors and assigns.\n\n10.5 Entire Agreement. This Agreement (including all exhibits and schedules) constitutes the entire agreement between the Parties regarding its subject matter and supersedes all prior and contemporaneous agreements, negotiations, and understandings, whether written or oral. No terms of any purchase order, invoice, or other document shall modify this Agreement unless signed by both Parties.\n\n10.6 Amendments. This Agreement may not be amended or modified except by a written instrument signed by authorized representatives of both Parties.\n\n10.7 Severability. If any provision of this Agreement is held invalid, illegal, or unenforceable, the remaining provisions shall continue in full force and effect. The invalid provision shall be modified to the minimum extent necessary to make it valid, legal, and enforceable while preserving the Parties'' intent.\n\n10.8 Waiver. No waiver of any provision or breach shall be effective unless in writing signed by the waiving Party. No waiver shall constitute a waiver of any other provision or subsequent breach.\n\n10.9 Force Majeure. Neither Party shall be liable for any delay or failure to perform due to causes beyond its reasonable control, including acts of God, natural disasters, war, terrorism, riots, embargoes, labor disputes, government orders, or failures of telecommunications or power supply. The affected Party shall provide prompt notice and use reasonable efforts to mitigate the impact.\n\n10.10 Relationship of the Parties. Nothing in this Agreement creates any relationship other than that of independent contracting parties. Neither Party has authority to bind or obligate the other.\n\n10.11 Counterparts and Electronic Signatures. This Agreement may be executed in counterparts, each of which shall be deemed an original, and all of which together shall constitute one agreement. Electronic signatures are valid and binding under the New York Electronic Signatures and Records Act (NY State Tech. Law Art. 3) and the federal ESIGN Act (15 U.S.C. § 7001 et seq.).\n\n10.12 Non-Compete (New York). The Parties acknowledge that non-compete provisions are disfavored under New York law and will be strictly scrutinized by courts. Any restrictive covenants must be reasonable in scope, duration, and geographic area, and necessary to protect legitimate business interests.\n\n10.13 Insurance. Consultant shall maintain appropriate insurance coverage, including professional liability (errors and omissions) insurance with coverage of at least {{insurance_amount}} (or $1,000,000 if not specified), and shall provide certificates of insurance upon Client''s request.\n\n10.14 GBL Section 349 Acknowledgment. The Parties acknowledge their obligations under New York General Business Law Section 349, which prohibits deceptive acts or practices in the conduct of any business, trade, or commerce. Neither Party shall engage in conduct that violates Section 349 in connection with this Agreement.\n\n10.15 Record Retention. Client shall retain a copy of this Agreement and records of all payments made hereunder for at least six (6) years following termination, consistent with applicable record-keeping requirements.\n\n10.16 Headings. Section headings are for convenience only and shall not affect interpretation.\n\n10.17 Construction. This Agreement shall be construed fairly, without presumption for or against either Party based on drafting.","type":"standard","order":10}]'::jsonb,
