  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Client Email","description":"Client email address","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Client Representative Name","description":"Full legal name of client representative","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Client Address","description":"Principal place of business","category":"party_a","type":"textarea","required":true,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Client Company Name","description":"Legal name of client entity","category":"party_a","type":"text","required":true,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Client Representative Title","description":"Title of authorized signatory","category":"party_a","type":"text","required":true,"autofillKey":"job_title"},{"id":"party_a_entity_type","token":"{{party_a_entity_type}}","label":"Client Entity Type","description":"e.g., corporation, LLC, partnership","category":"party_a","type":"text","required":false},{"id":"party_a_state","token":"{{party_a_state}}","label":"Client State of Organization","description":"State where client entity is organized","category":"party_a","type":"text","required":false},{"id":"party_b_email","token":"{{party_b_email}}","label":"Consultant Email","description":"Consultant email address","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Consultant Name","description":"Full legal name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Consultant Address","description":"Business address","category":"party_b","type":"textarea","required":true},{"id":"party_b_company","token":"{{party_b_company}}","label":"Consultant Company Name","description":"Business or DBA name","category":"party_b","type":"text","required":false},{"id":"party_b_title","token":"{{party_b_title}}","label":"Consultant Title","description":"Title if applicable","category":"party_b","type":"text","required":false},{"id":"party_b_entity_type","token":"{{party_b_entity_type}}","label":"Consultant Entity Type","description":"e.g., sole proprietor, LLC, corporation","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"Agreement start date","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"Expiration Date","description":"Agreement end date (if applicable)","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"New York county for dispute resolution","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period (Days)","description":"Days notice required for termination","category":"terms","type":"number","required":false},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period (Years)","description":"Duration of confidentiality obligations","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour if applicable","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Fixed Fee / Project Amount","description":"Total fee amount if applicable","category":"financial","type":"currency","required":false},{"id":"liability_cap","token":"{{liability_cap}}","label":"Liability Cap","description":"Maximum liability amount if different from fees","category":"financial","type":"currency","required":false},{"id":"insurance_amount","token":"{{insurance_amount}}","label":"Required Insurance Coverage","description":"Minimum professional liability insurance amount","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services Description","description":"Detailed description of consulting services or reference to Exhibit A","category":"project","type":"textarea","required":true}]'::jsonb,
